import java.util.HashMap;
import java.util.Map;

public class Solution {

    /**
     * Generates a map where keys are XOR sums of all subsets of the input array,
     * and values are the maximum size of a subset achieving that XOR sum.
     * @param arr The input array.
     * @return A map of XOR sum -> max size.
     */
    private Map<Long, Long> generateMap(long[] arr) {
        Map<Long, Long> m = new HashMap<>();
        int len = arr.length;

        // Iterate through all 2^len subsets
        for (int i = 0; i < (1 << len); i++) {
            long xorSum = 0;
            long size = 0;

            for (int j = 0; j < len; j++) {
                if (((i >> j) & 1) == 1) {
                    xorSum = xorSum ^ arr[j];
                    size++;
                }
            }

            // Update map: keep the maximum size for this XOR sum
            if (!m.containsKey(xorSum) || size > m.get(xorSum)) {
                m.put(xorSum, size);
            }
        }
        return m;
    }

    public long solve(long[] nums, long target) {
        int N = nums.length;
        if (N == 0) {
            return target == 0 ? 0 : -1;
        }

        int NA = N / 2;
        // Extract subarrays A and B
        long[] A = new long[NA];
        long[] B = new long[N - NA];

        for (int i = 0; i < NA; i++) {
            A[i] = nums[i];
        }
        for (int i = 0; i < N - NA; i++) {
            B[i] = nums[NA + i];
        }

        // Step 1: Process half A
        Map<Long, Long> mA = generateMap(A);

        long maxKeptSize = -1;

        // Step 2: Process half B
        int NB = N - NA;

        // Iterate through all 2^NB subsets of B
        for (int i = 0; i < (1 << NB); i++) {
            long xorB = 0;
            long sizeB = 0;

            for (int j = 0; j < NB; j++) {
                if (((i >> j) & 1) == 1) {
                    xorB = xorB ^ B[j];
                    sizeB++;
                }
            }

            // Required XOR sum from A
            long requiredXA = xorB ^ target;

            if (mA.containsKey(requiredXA)) {
                long sizeA = mA.get(requiredXA);
                long currentTotalSize = sizeA + sizeB;

                if (currentTotalSize > maxKeptSize) {
                    maxKeptSize = currentTotalSize;
                }
            }
        }

        // Step 3: Calculate result
        if (maxKeptSize == -1) {
            return -1;
        } else {
            // Minimum removed = Total length - Maximum kept size
            return (long)N - maxKeptSize;
        }
    }
}
