        let mut current_count: Int64 = 0;

        for j in 0..n {
            if (i >> j) & 1 == 1 {
                current_xor ^= half[j];
                current_count += 1;
            }
        }

        // Update the map with the minimum count found so far for this XOR sum
        let entry = m.entry(current_xor).or_insert(100); // Use a value larger than N=40 as initial large value
        *entry = min(*entry, current_count);
