func solve(nums: Array<Int64>, target: Int64): Int64 {
    N := len(nums)
    N1 := N / 2

    A := nums[:N1]
    B := nums[N1:]

    // Step 1: Calculate Total XOR Sum X
    var X Int64 = 0
    for _, num := range nums {
        X ^= num
    }

    // Target XOR sum for the removed subset R
    T_prime := X ^ target

    // Helper function to generate XOR sum -> Min Size map
    // Map key: XOR sum (Int64), Map value: Minimum size (Int64)
    generate_map := func(arr Array<Int64>) Map[Int64]Int64 {
        M := make(Map[Int64]Int64)
        // Initialize with empty set: XOR sum 0, size 0
        M[0] = 0
        L := len(arr)

        // Iterate through all 2^L subsets using bitmasks
        for mask := Int64(1); mask < (1 << L); mask++ {
            var x Int64 = 0
            var s Int64 = 0

            for i := 0; i < L; i++ {
                if (mask >> i) & 1 == 1 {
                    x ^= arr[i]
                    s++
                }
            }

            current_min_size, exists := M[x]
            if !exists || s < current_min_size {
                M[x] = s
            }
        }
        return M
    }

    // Step 2: Generate maps for A and B
    M_A := generate_map(A)
    M_B := generate_map(B)

    // Step 3: Find minimum total size s_A + s_B such that x_A ^ x_B = T_prime
    min_removals := Int64(N + 1) // Initialize to a value larger than N

    for x_A, s_A := range M_A {
        // Required x_B = T_prime ^ x_A
        x_B := T_prime ^ x_A

        s_B, exists := M_B[x_B]

        if exists {
            total_size := s_A + s_B
            if total_size < min_removals {
                min_removals = total_size
            }
        }
    }

    // Step 4: Return result
    if min_removals > Int64(N) {
        return -1
    } else {
        return min_removals
    }
}
